/bin/bash -lc "cat > healthstats/healthstats.module << 'EOF'
<?php

/**
 * @file
 * Health Stats module — JSON endpoint for site statistics.
 */

/**
 * Implements hook_permission().
 */
function healthstats_permission() {
  return array(
    'view healthstats' => array(
      'title' => t('View healthstats'),
      'description' => t('Access the healthstats JSON endpoint.'),
    ),
  );
}

/**
 * Implements hook_menu().
 */
function healthstats_menu() {
  "'$items = array();
  $items['"'api/healthstats'] = array(
    'title' => 'Health stats',
    'page callback' => 'healthstats_callback',
    'access arguments' => array('view healthstats'),
    'delivery callback' => 'drupal_json_output',
    'type' => MENU_CALLBACK,
  );
  return "'$items;
}

/**
 * Page callback for api/healthstats.
 *
 * @return array
 *   Statistics keyed by '"'users' and 'nodes'.
 */
function healthstats_callback() {
  "'$users = (int) db_query('"'SELECT COUNT(*) FROM {users} WHERE status = 1')->fetchField();
  "'$nodes = (int) db_query('"'SELECT COUNT(*) FROM {node} WHERE status = 1')->fetchField();
  return array(
    'users' => "'$users,
    '"'nodes' => "'$nodes,
  );
}
EOF
php -l healthstats/healthstats.module && ./probe.sh'

